package com.speedster.payload

import android.content.Context
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import com.speedster.DynamicEntry
import java.io.File

class PayloadEntry : DynamicEntry {
    private var isOverlayShowing by mutableStateOf(false)

    override @Composable fun Render(context: Context, resDir: File) {
        // Reset on start
        LaunchedEffect(Unit) {
            DynamicEntry.log("🕹️ Manual Control Mode Active")

            // Still hook keys so we can exit
            DynamicEntry.keyInterceptor = { event ->
                if (isOverlayShowing && event.keyCode == android.view.KeyEvent.KEYCODE_BACK) {
                    isOverlayShowing = false
                    DynamicEntry.overlayContent = null
                    true 
                } else {
                    false
                }
            }
        }

        // Update the global slot
        SideEffect {
            if (isOverlayShowing) {
                DynamicEntry.overlayContent = { SimpleOverlay() }
            } else {
                DynamicEntry.overlayContent = null
            }
        }

        // The Controller UI
        Box(
            modifier = Modifier.fillMaxSize().background(Color(0xFF1A1A1A)),
            contentAlignment = Alignment.Center
        ) {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Text("SYSTEM HIJACK TESTER", color = Color.White, modifier = Modifier.padding(bottom = 20.dp))

                Button(
                    onClick = { 
                        isOverlayShowing = !isOverlayShowing 
                        DynamicEntry.log("Button Clicked: Overlay is now $isOverlayShowing")
                    },
                    colors = ButtonDefaults.buttonColors(containerColor = if(isOverlayShowing) Color.Red else Color.Green)
                ) {
                    Text(if(isOverlayShowing) "DISMISS OVERLAY" else "SHOW OVERLAY", color = Color.White)
                }

                if (DynamicEntry.activeAccessibilityService == null) {
                    Text(
                        "⚠️ SERVICE DISCONNECTED\nEnable in Accessibility Settings!",
                        color = Color.Yellow,
                        modifier = Modifier.padding(top = 20.dp),
                        textAlign = androidx.compose.ui.text.style.TextAlign.Center
                    )
                }
            }
        }
    }

    @Composable
    fun SimpleOverlay() {
        // A massive red box that covers EVERYTHING
        Box(
            modifier = Modifier
                .fillMaxSize()
                .background(Color.Red.copy(alpha = 0.5f)),
            contentAlignment = Alignment.Center
        ) {
            Text(
                "SYSTEM CAPTURED",
                color = Color.White,
                fontSize = 40.sp,
                style = MaterialTheme.typography.headlineLarge
            )
        }
    }
}

